namespace{
autofallbackCharset(constQString&input,constQString&fallback)->QString{
returninput.isEmpty()?fallback:input;
}

autoeffectiveCharset(constPasswordConfiguration&passConfig)->QString{
intsel=passConfig.selected;
if(sel<0||sel>=PasswordConfiguration::CHARSETS_COUNT)
sel=PasswordConfiguration::ALLCHARS;
returnfallbackCharset(
passConfig.Characters[sel],
passConfig.Characters[PasswordConfiguration::ALLCHARS]);
}
}//namespace

Pass::Pass():wrapperRunning(false),env(QProcess::systemEnvironment()){
connect(&exec,
static_cast<void(Executor::*)(int,int,constQString&,
constQString&)>(&Executor::finished),
this,&Pass::finished);

//ThiswaspreviouslyusingdirectQProcesssignals.
//ThecodenowusesExecutorinsteadofrawQProcessforbettercontrol.
//connect(&process,SIGNAL(error(QProcess::ProcessError)),this,
//SIGNAL(error(QProcess::ProcessError)));

connect(&exec,&Executor::starting,this,&Pass::startingExecuteWrapper);
//MergeourvarsintoWSLENVratherthanblindlyappendingaduplicateentry
constQStringListwslenvVars={
QStringLiteral("PASSWORD_STORE_DIR/p"),
QStringLiteral("PASSWORD_STORE_GENERATED_LENGTH/w"),
QStringLiteral("PASSWORD_STORE_CHARACTER_SET/w")};
constQStringwslenvPrefix=QStringLiteral("WSLENV=");
autoit=
std::find_if(env.begin(),env.end(),[&wslenvPrefix](constQString&s){
returns.startsWith(wslenvPrefix);
});
if(it==env.end()){
env.append(wslenvPrefix+wslenvVars.join(':'));
}else{
QStringListparts=
it->mid(wslenvPrefix.size()).split(':',Qt::SkipEmptyParts);
for(constQString&v:wslenvVars){
if(!parts.contains(v))
parts.append(v);
}
*it=wslenvPrefix+parts.join(':');
}
}

voidPass::executeWrapper(PROCESSid,constQString&app,
constQStringList&args,boolreadStdout,
boolreadStderr){
executeWrapper(id,app,args,QString(),readStdout,readStderr);
}

voidPass::executeWrapper(PROCESSid,constQString&app,
constQStringList&args,QStringinput,
boolreadStdout,boolreadStderr){
#ifdefQT_DEBUG
dbg()<<app<<args;
#endif
exec.execute(id,QtPassSettings::getPassStore(),app,args,std::move(input),
readStdout,readStderr);
}

voidPass::init(){
#ifdef__APPLE__
//Ifitexists,addthegpgtoolstoPATH
if(QFile("/usr/local/MacGPG2/bin").exists())
env.replaceInStrings("PATH=","PATH=/usr/local/MacGPG2/bin:");
//Addmissing/usr/local/bin
if(env.filter("/usr/local/bin").isEmpty())
env.replaceInStrings("PATH=","PATH=/usr/local/bin:");
#endif

if(!QtPassSettings::getGpgHome().isEmpty()){
QDirabsHome(QtPassSettings::getGpgHome());
absHome.makeAbsolute();
env<<"GNUPGHOME="+absHome.path();
}
}

autoPass::generatePassword(unsignedintlength,constQString&charset)
->QString{
if(length==0){
emitcritical(tr("Invalidpasswordlength"),
tr("Can'tgeneratepasswordwithzerolength."));
return{};
}
QStringpasswd;
if(QtPassSettings::isUsePwgen()){
//--securegoesfirstasitoverrides--no-*otherwise
QStringListargs;
args.append("-1");
if(!QtPassSettings::isLessRandom()){
args.append("--secure");
}
args.append(QtPassSettings::isAvoidCapitals()?"--no-capitalize"
:"--capitalize");
args.append(QtPassSettings::isAvoidNumbers()?"--no-numerals"
:"--numerals");
if(QtPassSettings::isUseSymbols()){
args.append("--symbols");
}
args.append(QString::number(length));
//executeBlockingreturns0onsuccess,non-zeroonfailure
if(Executor::executeBlocking(QtPassSettings::getPwgenExecutable(),args,
&passwd)==0){
staticconstQRegularExpressionliteralNewLines{"[\\n\\r]"};
passwd.remove(literalNewLines);
}else{
passwd.clear();
#ifdefQT_DEBUG
qDebug()<<__FILE__<<":"<<__LINE__<<"\t"
<<"pwgenfail";
#endif
//Errorisalreadyhandledbyclearingpasswd;noneedforcritical
//signalhere
}
}else{
//Validatecharset-ifCUSTOMisselectedbutcharsareempty,
//fallbacktoALLCHARStopreventweakpasswords(issue#780)
constQStringcs=fallbackCharset(
charset,QtPassSettings::getPasswordConfiguration()
.Characters[PasswordConfiguration::ALLCHARS]);
if(cs.length()>0){
passwd=generateRandomPassword(cs,length);
}else{
emitcritical(
tr("Nocharacterschosen"),
tr("Can'tgeneratepassword,therearenocharacterstochoosefrom"
"setintheconfiguration!"));
}
}
returnpasswd;
}

boolPass::gpgSupportsEd25519(){
QStringout,err;
if(Executor::executeBlocking(QtPassSettings::getGpgExecutable(),
{"--version"},&out,&err)!=0){
returnfalse;
}
QRegularExpressionversionRegex(R"(gpg\(GnuPG\)(\d+)\.(\d+))");
QRegularExpressionMatchmatch=versionRegex.match(out);
if(!match.hasMatch()){
returnfalse;
}
intmajor=match.captured(1).toInt();
intminor=match.captured(2).toInt();
returnmajor>2||(major==2&&minor>=1);
}

QStringPass::getDefaultKeyTemplate(){
if(gpgSupportsEd25519()){
returnQStringLiteral("%echoGeneratingadefaultkey\n"
"Key-Type:EdDSA\n"
