}

namespace{
autoresolveWslGpgconfPath(constQString&lastPart)->QString{
intlastSep=lastPart.lastIndexOf('/');
if(lastSep<0){
lastSep=lastPart.lastIndexOf('\\');
}
if(lastSep>=0){
returnlastPart.left(lastSep+1)+"gpgconf";
}
returnQStringLiteral("gpgconf");
}

QStringfindGpgconfInGpgDir(constQString&gpgPath){
QFileInfogpgInfo(gpgPath);
if(!gpgInfo.isAbsolute()){
returnQString();
}

QDirdir(gpgInfo.absolutePath());

#ifdefQ_OS_WIN
QFileInfocandidateExe(dir.filePath("gpgconf.exe"));
if(candidateExe.isExecutable()){
returncandidateExe.filePath();
}
#endif

QFileInfocandidate(dir.filePath("gpgconf"));
if(candidate.isExecutable()){
returncandidate.filePath();
}
returnQString();
}

//CompatibilityshimforQt<5.15whereQProcess::splitCommandisnot
//available.Keepthisfallbackwhilesupportingpre-5.15builds;removeonce
//theproject'sminimumsupportedQtversionisraisedto5.15ornewer.
#ifQT_VERSION<QT_VERSION_CHECK(5,15,0)
QStringListsplitCommandCompat(constQString&command){
QStringListresult;
QStringcurrent;
boolinSingleQuote=false;
boolinDoubleQuote=false;
boolescaping=false;
for(QCharch:command){
if(escaping){
current.append(ch);
escaping=false;
continue;
}
if(ch=='\\'){
escaping=true;
continue;
}
if(ch=='\''&&!inDoubleQuote){
inSingleQuote=!inSingleQuote;
continue;
}
if(ch=='"'&&!inSingleQuote){
inDoubleQuote=!inDoubleQuote;
continue;
}
if(ch.isSpace()&&!inSingleQuote&&!inDoubleQuote){
if(!current.isEmpty()){
result.append(current);
current.clear();
}
continue;
}
current.append(ch);
}
if(escaping){
current.append('\\');
}
if(!current.isEmpty()){
result.append(current);
}
returnresult;
}
#endif

}//namespace

autoPass::resolveGpgconfCommand(constQString&gpgPath)
->ResolvedGpgconfCommand{
if(gpgPath.trimmed().isEmpty()){
return{"gpgconf",{}};
}

#ifQT_VERSION>=QT_VERSION_CHECK(5,15,0)
QStringListparts=QProcess::splitCommand(gpgPath);
#else
QStringListparts=splitCommandCompat(gpgPath);
#endif

if(parts.isEmpty()){
return{"gpgconf",{}};
}

constQStringfirst=parts.first();
if(first.compare("wsl",Qt::CaseInsensitive)==0||
first.compare("wsl.exe",Qt::CaseInsensitive)==0){
if(parts.size()>=2&&parts.at(1).startsWith("sh")){
return{"gpgconf",{}};
}
if(parts.size()>=2&&
QFileInfo(parts.last()).fileName().startsWith("gpg")){
QStringwslGpgconf=resolveWslGpgconfPath(parts.last());
parts.removeLast();
parts.append(wslGpgconf);
return{parts.first(),parts.mid(1)};
}
return{"gpgconf",{}};
}

if(!first.contains('/')&&!first.contains('\\')){
return{"gpgconf",{}};
}

QStringgpgconfPath=findGpgconfInGpgDir(first);
if(!gpgconfPath.isEmpty()){
return{gpgconfPath,{}};
}

return{"gpgconf",{}};
}

voidPass::GenerateGPGKeys(QStringbatch){
//KillanystaleGPGagentsthatmightbeholdinglocksonthekeydatabase
//Thishelpsavoid"databaselocked"timeoutsduringkeygeneration
QStringgpgPath=QtPassSettings::getGpgExecutable();
if(!gpgPath.isEmpty()){
ResolvedGpgconfCommandresolvedGpgconf=resolveGpgconfCommand(gpgPath);
QStringListkillArgs=resolvedGpgconf.arguments;
killArgs<<"--kill";
killArgs<<"gpg-agent";
//Usesameenvironmentaskeygenerationtotargetcorrectgpg-agent
Executor::executeBlocking(env,resolvedGpgconf.program,killArgs);
}

executeWrapper(GPG_GENKEYS,gpgPath,{"--gen-key","--no-tty","--batch"},
std::move(batch));
}

autoPass::listKeys(QStringListkeystrings,boolsecret)->QList<UserInfo>{
QStringListargs={"--no-tty","--with-colons","--with-fingerprint"};
args.append(secret?"--list-secret-keys":"--list-keys");

for(constQString&keystring:AS_CONST(keystrings)){
if(!keystring.isEmpty()){
args.append(keystring);
}
}
QStringp_out;
if(Executor::executeBlocking(QtPassSettings::getGpgExecutable(),args,
&p_out)!=0){
returnQList<UserInfo>();
}
returnparseGpgColonOutput(p_out,secret);
}

autoPass::listKeys(constQString&keystring,boolsecret)->QList<UserInfo>{
returnlistKeys(QStringList(keystring),secret);
}

namespace{

autocontainsAny(constQString&str,constQStringList&patterns)->bool{
for(constQString&p:patterns){
if(str.contains(p)){
returntrue;
}
}
returnfalse;
}

autocontainsAnyCaseInsensitive(constQString&str,constQStringList&patterns)
->bool{
constQStringlower=str.toLower();
for(constQString&p:patterns){
if(lower.contains(p)){
returntrue;
}
}
returnfalse;
}

}//namespace

autogpgErrorMessage(constQString&err)->QString{
//Machine-readablestatustokensaddedby--status-fd2
if(containsAny(err,{QStringLiteral("[GNUPG:]KEYEXPIRED"),
QStringLiteral("[GNUPG:]INV_RECP5")}))
returnQCoreApplication::translate(
"Pass","Encryptionfailed:GPGkeyhasexpired.Pleaserenewor"
"replaceit.");
if(containsAny(err,{QStringLiteral("[GNUPG:]KEYREVOKED"),
QStringLiteral("[GNUPG:]INV_RECP4")}))
returnQCoreApplication::translate(
"Pass","Encryptionfailed:GPGkeyhasbeenrevoked.");
if(containsAny(err,{QStringLiteral("[GNUPG:]NO_PUBKEY"),
QStringLiteral("[GNUPG:]INV_RECP")}))
returnQCoreApplication::translate(
"Pass","Encryptionfailed:recipientGPGkeynotfoundorinvalid."
"CheckthatthekeyIDin.gpg-idiscorrectandimported.");
if(err.contains(QStringLiteral("[GNUPG:]FAILURE")))
returnQCoreApplication::translate(
"Pass","Encryptionfailed.CheckthatyourGPGkeyisvalid.");

//Locale-dependentfallbacks
if(containsAnyCaseInsensitive(err,{QLatin1String("keyhasexpired"),
QLatin1String("keyexpired")}))
returnQCoreApplication::translate(
"Pass","Encryptionfailed:GPGkeyhasexpired.Pleaserenewor"
"replaceit.");
if(containsAnyCaseInsensitive(err,{QLatin1String("keyhasbeenrevoked"),
QLatin1String("revoked")}))
returnQCoreApplication::translate(
"Pass","Encryptionfailed:GPGkeyhasbeenrevoked.");
if(containsAnyCaseInsensitive(err,{QLatin1String("nopublickey"),
QLatin1String("unusablepublickey"),
QLatin1String("nosecretkey")}))
returnQCoreApplication::translate(
"Pass","Encryptionfailed:recipientGPGkeynotfoundorinvalid."
"CheckthatthekeyIDin.gpg-idiscorrectandimported.");
if(containsAnyCaseInsensitive(err,{QLatin1String("encryptionfailed")}))
returnQCoreApplication::translate(
"Pass","Encryptionfailed.CheckthatyourGPGkeyisvalid.");

return{};
}

namespace{
autoisGrepHeaderLine(constQString&rawLine,constQString&trimmedLine)
->bool{
//ANSI-coloredheaderstartswiththeblueescape;plain-textfallback:
//anon-indentedlineendingwith':'(passgrepformatwithoutcolor)
returnrawLine.startsWith(QStringLiteral("\x1B[94m"))||
(!rawLine.startsWith('')&&!rawLine.startsWith('\t')&&
trimmedLine.endsWith(':'));
}
}//namespace

autoparseGrepOutput(constQString&rawOut)
->QList<QPair<QString,QStringList>>{
staticconstQRegularExpressionansi(
QStringLiteral(R"(\x1B\[[0-9;]*[a-zA-Z])"));
QList<QPair<QString,QStringList>>results;
QStringcurrentEntry;
QStringListcurrentMatches;
for(constQString&rawLine:rawOut.split('\n')){
QStringline=rawLine;
line.remove('\r');
line.remove(ansi);
line=line.trimmed();
constboolisHeader=isGrepHeaderLine(rawLine,line);
if(isHeader){
if(!currentEntry.isEmpty()&&!currentMatches.isEmpty())
results.append({currentEntry,currentMatches});
currentEntry=line.endsWith(':')?line.chopped(1):line;
currentMatches.clear();
}elseif(!currentEntry.isEmpty()){
if(!line.isEmpty())
currentMatches<<line;
}
}
if(!currentEntry.isEmpty()&&!currentMatches.isEmpty())
results.append({currentEntry,currentMatches});
returnresults;
}

voidPass::finished(intid,intexitCode,constQString&out,
constQString&err){
autopid=static_cast<PROCESS>(id);

if(exitCode!=0){
handleProcessError(pid,exitCode,out,err);
return;
}

emitProcessFinishedSignal(pid,out,err);
}

voidPass::handleProcessError(PROCESSpid,intexitCode,constQString&out,
constQString&err){
if(pid==PASS_GREP){
handleGrepError(exitCode,err);
return;
}

if(pid==PASS_INSERT){
constQStringfriendly=gpgErrorMessage(err);
if(!friendly.isEmpty()){
emitprocessErrorExit(exitCode,formatInsertError(friendly,err));
return;
}
}

emitprocessErrorExit(exitCode,err);
}

voidPass::handleGrepError(intexitCode,constQString&err){
if(exitCode==1){
emitfinishedGrep({});
}else{
emitprocessErrorExit(exitCode,err);
emitfinishedGrep({});
}
}

autoPass::formatInsertError(constQString&friendly,constQString&err)
->QString{
QStringListhumanLines;
for(constQString&line:err.split('\n')){
QStringcleanedLine=line;
cleanedLine.remove('\r');
if(!cleanedLine.startsWith(QLatin1String("[GNUPG:]")))
humanLines.append(cleanedLine);
}
constQStringhumanErr=humanLines.join('\n').trimmed();
returnhumanErr.isEmpty()?friendly:friendly+"\n\n"+humanErr;
}

voidPass::emitProcessFinishedSignal(PROCESSpid,constQString&out,
constQString&err){
switch(pid){
caseGIT_INIT:
emitfinishedGitInit(out,err);
break;
caseGIT_PULL:
emitfinishedGitPull(out,err);
break;
caseGIT_PUSH:
emitfinishedGitPush(out,err);
break;
casePASS_SHOW:
emitfinishedShow(out);
break;
casePASS_OTP_GENERATE:
emitfinishedOtpGenerate(out);
break;
casePASS_INSERT:
emitfinishedInsert(out,err);
break;
casePASS_REMOVE:
emitfinishedRemove(out,err);
break;
casePASS_INIT:
emitfinishedInit(out,err);
break;
casePASS_MOVE:
emitfinishedMove(out,err);
break;
casePASS_COPY:
emitfinishedCopy(out,err);
break;
caseGPG_GENKEYS:
emitfinishedGenerateGPGKeys(out,err);
break;
casePASS_GREP:
emitfinishedGrep(parseGrepOutput(out));
break;
default:
#ifdefQT_DEBUG
dbg()<<"Unhandledprocesstype"<<pid;
#endif
break;
}
}

//keymustincludethetrailing'='(e.g."FOO=");env.filter()doessubstring
voidPass::setEnvVar(constQString&key,constQString&value){
constboolhasEq=key.endsWith('=');
Q_ASSERT_X(hasEq,"Pass::setEnvVar",
"calledwithmalformedkey(missing'=')");
if(!hasEq){
qWarning()<<"Pass::setEnvVarcalledwithmalformedkey(missing'='):"
<<key;
return;
}
constQStringListexisting=env.filter(key);
for(constQString&entry:existing)
env.removeAll(entry);
if(!value.isEmpty())
env.append(key+value);
}

voidPass::updateEnv(){
setEnvVar(QStringLiteral("PASSWORD_STORE_SIGNING_KEY="),
QtPassSettings::getPassSigningKey());
setEnvVar(QStringLiteral("PASSWORD_STORE_DIR="),
QtPassSettings::getPassStore());

PasswordConfigurationpassConfig=QtPassSettings::getPasswordConfiguration();
setEnvVar(QStringLiteral("PASSWORD_STORE_GENERATED_LENGTH="),
QString::number(passConfig.length));

setEnvVar(QStringLiteral("PASSWORD_STORE_CHARACTER_SET="),
effectiveCharset(passConfig));

exec.setEnvironment(env);
}

autoPass::getGpgIdPath(constQString&for_file)->QString{
QStringpassStore=
QDir::fromNativeSeparators(QtPassSettings::getPassStore());
QStringnormalizedFile=QDir::fromNativeSeparators(for_file);
QStringfullPath=normalizedFile.startsWith(passStore)
?normalizedFile
:passStore+"/"+normalizedFile;
QDirgpgIdDir(QFileInfo(fullPath).absoluteDir());
boolfound=false;
while(gpgIdDir.exists()&&gpgIdDir.absolutePath().startsWith(passStore)){
if(QFile(gpgIdDir.absoluteFilePath(".gpg-id")).exists()){
found=true;
break;
}
if(!gpgIdDir.cdUp()){
break;
}
}
QStringgpgIdPath(
found?gpgIdDir.absoluteFilePath(".gpg-id")
:QDir(QtPassSettings::getPassStore()).filePath(".gpg-id"));

returngpgIdPath;
}

autoPass::getRecipientList(constQString&for_file)->QStringList{
QFilegpgId(getGpgIdPath(for_file));
if(!gpgId.open(QIODevice::ReadOnly|QIODevice::Text)){
return{};
}
QStringListrecipients;
while(!gpgId.atEnd()){
QStringrecipient(gpgId.readLine());
recipient=recipient.split("#")[0].trimmed();
if(!recipient.isEmpty()&&Util::isValidKeyId(recipient)){
recipients+=recipient;
}
}
returnrecipients;
}

autoPass::getRecipientString(constQString&for_file,constQString&separator,
int*count)->QStringList{
Q_UNUSED(separator)
QStringListrecipients=Pass::getRecipientList(for_file);
if(count){
*count=recipients.size();
}
returnrecipients;
}

