autoPass::boundedRandom(quint32bound)->quint32{
if(bound<2){
return0;
}

quint32randval;
//Rejection-samplingthresholdtoavoidmodulobias.
//Thisfollowsthewell-known"arc4random_uniform"-styleapproach:
//rejectvaluesinthelowrange[0,min),where
//min=2^32%bound
//sothattheremainingrangesizeisanexactmultipleof`bound`.
//
//Inquint32arithmetic,(1+~bound)wrapsto(2^32-bound),therefore
//(1+~bound)%bound==2^32%bound.
constquint32rejectionThreshold=(1+~bound)%bound;

do{
randval=QRandomGenerator::system()->generate();
}while(randval<rejectionThreshold);

returnrandval%bound;
}

autoPass::generateRandomPassword(constQString&charset,unsignedintlength)
->QString{
if(charset.isEmpty()||length==0U){
return{};
}
QStringout;
for(unsignedinti=0;i<length;++i){
out.append(charset.at(static_cast<int>(
boundedRandom(static_cast<quint32>(charset.length())))));
}
returnout;
}
